#include <vector>

std::vector<long long> solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    std::vector<long long> ans;
    for (const auto& q : queries) {
        long long l = q[0], r = q[1], t = q[2];
        std::unordered_map<long long, int> freq;
        for (long long i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }
        long long max_freq = -1;
        long long best_num = -1;
        for (const auto& [num, cnt] : freq) {
            if (cnt >= t) {
                if (cnt > max_freq || (cnt == max_freq && num < best_num)) {
                    max_freq = cnt;
                    best_num = num;
                }
            }
        }
        ans.push_back(best_num);
    }
    return ans;
}

